import java.util.*;

public class Solution {
    public static long[] solve(long n) {
        // Map to store the sum x and the count of ways (a, b) it can be formed.
        // Since we iterate with a <= b, each unique pair (a, b) generates a unique entry in the map based on x.
        Map<Long, Integer> sumCounts = new HashMap<>();

        // Iterate over a, starting from 1.
        // Stop condition: 2*a^3 > n, since a <= b, x >= 2*a^3.
        for (long a = 1; ; a++) {
            long a3 = a * a * a;

            // Check if 2*a^3 exceeds n. We use division to prevent potential overflow if n was close to Long.MAX_VALUE, 
            // though for n <= 10^9 this is mainly a cleaner check.
            if (a3 > n / 2) {
                break;
            }

            // Iterate over b, starting from a.
            // Stop condition: a^3 + b^3 > n.
            for (long b = a; ; b++) {
                long b3 = b * b * b;

                // Check if a^3 + b^3 exceeds n. Check if b^3 > n - a^3.
                // Since n - a3 >= 0 (due to outer loop condition), this check is safe.
                if (b3 > n - a3) {
                    break; // b is too large for this a
                }

                long x = a3 + b3;

                // Update the count for x
                sumCounts.put(x, sumCounts.getOrDefault(x, 0) + 1);
            }
        }

        // Collect all good integers (where count >= 2)
        List<Long> goodIntegers = new ArrayList<>();
        for (Map.Entry<Long, Integer> entry : sumCounts.entrySet()) {
            if (entry.getValue() >= 2) {
                goodIntegers.add(entry.getKey());
            }
        }

        // Sort the results in ascending order
        Collections.sort(goodIntegers);

        // Convert List<Long> to long[]
        long[] result = new long[goodIntegers.size()];
        for (int i = 0; i < goodIntegers.size(); i++) {
            result[i] = goodIntegers.get(i);
        }

        return result;
    }
}

