import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {
    public static long[] solve(long n) {
        Map<Long, Integer> counts = new HashMap<>();

        // Iterate over a, where a >= 1
        // Since a <= b, we must have 2*a^3 <= a^3 + b^3 <= n.
        long a = 1;
        while (true) {
            long a3 = a * a * a;
            // Check if the smallest possible sum (a^3 + a^3) exceeds n
            if (2 * a3 > n) {
                break;
            }

            // Iterate over b, where b >= a
            long b = a;
            while (true) {
                long b3 = b * b * b;
                long sum = a3 + b3;

                if (sum > n) {
                    // Since b is increasing, all subsequent sums will also exceed n
                    break;
                }

                // Record the number of ways this sum can be formed
                counts.put(sum, counts.getOrDefault(sum, 0) + 1);

                b++;
            }
            a++;
        }

        // Collect all good integers (those appearing at least twice)
        List<Long> goodIntegers = new ArrayList<>();
        for (Map.Entry<Long, Integer> entry : counts.entrySet()) {
            if (entry.getValue() >= 2) {
                goodIntegers.add(entry.getKey());
            }
        }

        // Sort them in ascending order
        Collections.sort(goodIntegers);

        // Convert List<Long> to long[]
        long[] result = new long[goodIntegers.size()];
        for (int i = 0; i < goodIntegers.size(); i++) {
            result[i] = goodIntegers.get(i);
        }

        return result;
    }
}

